// MarketPositionsHandlerWithService creates a service-injected positions handler for all users
func MarketPositionsHandlerWithService(svc dmarkets.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		marketID, err := parseMarketID(mux.Vars(r)["marketId"])
		if err != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		positions, err := svc.GetMarketPositions(r.Context(), marketID)
		if err != nil {
			writePositionsError(w, marketID, err)
			return
		}

		responses := mapPositionsToResponses(positions)

		if err := handlers.WriteResult(w, http.StatusOK, responses); err != nil {
			log.Printf("Error encoding positions response: %v", err)
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
		}
	}
}

// MarketUserPositionHandlerWithService creates a service-injected handler for a specific user's position
func MarketUserPositionHandlerWithService(svc dmarkets.ServiceInterface) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodGet {
			_ = handlers.WriteFailure(w, http.StatusMethodNotAllowed, handlers.ReasonMethodNotAllowed)
			return
		}

		marketID, username, err := parseMarketUserParams(mux.Vars(r))
		if err != nil {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
			return
		}

		position, err := svc.GetUserPositionInMarket(r.Context(), marketID, username)
		if err != nil {
			writeUserPositionError(w, marketID, username, err)
			return
		}

		if err := handlers.WriteResult(w, http.StatusOK, newUserPositionResponse(position)); err != nil {
			log.Printf("Error encoding user position response: %v", err)
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
		}
	}
}

func parseMarketID(marketIDStr string) (int64, error) {
	if marketIDStr == "" {
		return 0, errors.New("Market ID is required")
	}

	marketID, err := strconv.ParseInt(marketIDStr, 10, 64)
	if err != nil {
		return 0, errors.New("Invalid market ID")
	}
	return marketID, nil
}

func writePositionsError(w http.ResponseWriter, marketID int64, err error) {
	switch err {
	case dmarkets.ErrMarketNotFound:
		_ = handlers.WriteFailure(w, http.StatusNotFound, reasonPositionsMarketNotFound)
	case dmarkets.ErrInvalidInput:
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
	default:
		log.Printf("Error getting market positions for market %d: %v", marketID, err)
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

func mapPositionsToResponses(positions []*dmarkets.UserPosition) []userPositionResponse {
	responses := make([]userPositionResponse, 0, len(positions))
	for _, pos := range positions {
		if pos == nil {
			continue
		}
		responses = append(responses, newUserPositionResponse(pos))
	}
	return responses
}

func parseMarketUserParams(vars map[string]string) (int64, string, error) {
	marketID, err := parseMarketID(vars["marketId"])
	if err != nil {
		return 0, "", err
	}

	username := vars["username"]
	if username == "" {
		return 0, "", errors.New("Username is required")
	}

	return marketID, username, nil
}

func writeUserPositionError(w http.ResponseWriter, marketID int64, username string, err error) {
	switch err {
	case dmarkets.ErrMarketNotFound:
		_ = handlers.WriteFailure(w, http.StatusNotFound, reasonPositionsMarketNotFound)
	case dmarkets.ErrUserNotFound:
		_ = handlers.WriteFailure(w, http.StatusNotFound, reasonPositionsUserNotFound)
	case dmarkets.ErrInvalidInput:
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
	default:
		log.Printf("Error getting user position for market %d, user %s: %v", marketID, username, err)
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
	}
}

package usershandlers

import (
	"errors"
	"net/http"
	"strings"

	"socialpredict/handlers"
	"socialpredict/handlers/users/dto"
	dusers "socialpredict/internal/domain/users"
	authsvc "socialpredict/internal/service/auth"
)

func writeProfileError(w http.ResponseWriter, err error, field string) {
	switch {
	case errors.Is(err, dusers.ErrUserNotFound):
		_ = handlers.WriteFailure(w, http.StatusNotFound, handlers.ReasonUserNotFound)
	case errors.Is(err, dusers.ErrInvalidUserData):
		_ = handlers.WriteFailure(w, http.StatusBadRequest, "INVALID_USER_DATA")
	case errors.Is(err, dusers.ErrInvalidCredentials):
		_ = handlers.WriteFailure(w, http.StatusUnauthorized, "INVALID_CREDENTIALS")
	default:
		message := err.Error()
		if isValidationError(message) {
			_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonValidationFailed)
			return
		}
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, profileFailureReason(field))
	}
}

func writeProfileJSONError(w http.ResponseWriter, statusCode int, message string) {
	_ = handlers.WriteFailure(w, statusCode, handlers.FailureReason(message))
}

func isValidationError(message string) bool {
	lower := strings.ToLower(message)
	return strings.Contains(lower, "invalid") ||
		strings.Contains(lower, "exceeds") ||
		strings.Contains(lower, "must") ||
		strings.Contains(lower, "cannot") ||
		strings.Contains(lower, "required")
}

func toPrivateUserResponse(user *dusers.User) dto.PrivateUserResponse {
	if user == nil {
		return dto.PrivateUserResponse{}
	}

	return dto.PrivateUserResponse{
		ID:                    user.ID,
		Username:              user.Username,
		DisplayName:           user.DisplayName,
		UserType:              user.UserType,
		InitialAccountBalance: user.InitialAccountBalance,
		AccountBalance:        user.AccountBalance,
		PersonalEmoji:         user.PersonalEmoji,
		Description:           user.Description,
		PersonalLink1:         user.PersonalLink1,
		PersonalLink2:         user.PersonalLink2,
		PersonalLink3:         user.PersonalLink3,
		PersonalLink4:         user.PersonalLink4,
		Email:                 user.Email,
		APIKey:                user.APIKey,
		MustChangePassword:    user.MustChangePassword,
	}
}

func profileFailureReason(field string) handlers.FailureReason {
	switch field {
	case "display name":
		return "DISPLAY_NAME_UPDATE_FAILED"
	case "description":
		return "DESCRIPTION_UPDATE_FAILED"
	case "emoji":
		return "EMOJI_UPDATE_FAILED"
	case "personal links":
		return "PERSONAL_LINKS_UPDATE_FAILED"
	default:
		return handlers.ReasonInternalError
	}
}

func profileAuthFailureReason(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch err.Message {
	case "Authorization header is required", "Invalid token":
		return handlers.ReasonInvalidToken
	case "Password change required":
		return handlers.ReasonPasswordChangeRequired
	case "User not found":
		return handlers.ReasonUserNotFound
	default:
		if err.StatusCode >= http.StatusInternalServerError {
			return handlers.ReasonInternalError
		}
		return handlers.ReasonInvalidToken
	}
}

package http

import (
	"context"
	"encoding/json"
	"net/http"
	"socialpredict/handlers"
	"socialpredict/handlers/cms/homepage"
	authsvc "socialpredict/internal/service/auth"
)

const (
	reasonHomepageAuthUnavailable handlers.FailureReason = "AUTH_SERVICE_UNAVAILABLE"
	reasonHomepageAdminRequired   handlers.FailureReason = "ADMIN_REQUIRED"
	reasonHomepageUpdateFailed    handlers.FailureReason = "HOMEPAGE_UPDATE_FAILED"
	reasonHomepageNotFound        handlers.FailureReason = "HOME_CONTENT_NOT_FOUND"
)

type Handler struct {
	svc  *homepage.Service
	auth authsvc.Authenticator
}

func NewHandler(svc *homepage.Service, auth authsvc.Authenticator) *Handler {
	return &Handler{svc: svc, auth: auth}
}

func (h *Handler) PublicGet(w http.ResponseWriter, r *http.Request) {
	item, err := h.svc.GetHome()
	if err != nil {
		_ = handlers.WriteFailure(w, http.StatusNotFound, reasonHomepageNotFound)
		return
	}

	_ = handlers.WriteResult(w, http.StatusOK, map[string]interface{}{
		"title":     item.Title,
		"format":    item.Format,
		"html":      item.HTML,
		"markdown":  item.Markdown, // optional to expose
		"version":   item.Version,
		"updatedAt": item.UpdatedAt,
	})
}

type updateReq struct {
	Title    string `json:"title"`
	Format   string `json:"format"`   // "markdown" | "html"
	Markdown string `json:"markdown"` // when format=markdown
	HTML     string `json:"html"`     // when format=html
	Version  uint   `json:"version"`
}

func (h *Handler) AdminUpdate(w http.ResponseWriter, r *http.Request) {
	// Validate admin access
	if h.auth == nil {
		_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonHomepageAuthUnavailable)
		return
	}
	admin, httpErr := h.auth.RequireAdmin(r)
	if httpErr != nil {
		_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAdminAuthError(httpErr))
		return
	}

	var in updateReq
	if err := json.NewDecoder(r.Body).Decode(&in); err != nil {
		_ = handlers.WriteFailure(w, http.StatusBadRequest, handlers.ReasonInvalidRequest)
		return
	}

	item, err := h.svc.UpdateHome(homepage.UpdateInput{
		Title:     in.Title,
		Format:    in.Format,
		Markdown:  in.Markdown,
		HTML:      in.HTML,
		Version:   in.Version,
		UpdatedBy: admin.Username,
	})
	if err != nil {
		_ = handlers.WriteFailure(w, http.StatusBadRequest, reasonHomepageUpdateFailed)
		return
	}

	_ = handlers.WriteResult(w, http.StatusOK, map[string]interface{}{
		"title":   item.Title,
		"format":  item.Format,
		"html":    item.HTML,
		"version": item.Version,
	})
}

// RequireAdmin middleware wrapper that can be used in routes when an authenticator is available.
func RequireAdmin(auth authsvc.Authenticator, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if auth == nil {
			_ = handlers.WriteFailure(w, http.StatusInternalServerError, reasonHomepageAuthUnavailable)
			return
		}
		if _, httpErr := auth.RequireAdmin(r); httpErr != nil {
			_ = handlers.WriteFailure(w, httpErr.StatusCode, reasonFromAdminAuthError(httpErr))
			return
		}
		next.ServeHTTP(w, r)
	}
}

// UsernameFromContext extracts username from request context (helper function)
func UsernameFromContext(ctx context.Context) string {
	// This is a placeholder - in practice you might store username in context
	// during authentication middleware
	return "admin" // fallback for now
}

func reasonFromAdminAuthError(err *authsvc.HTTPError) handlers.FailureReason {
	if err == nil {
		return handlers.ReasonInternalError
	}

	switch err.Message {
	case "Authorization header is required", "Invalid token":
		return handlers.ReasonInvalidToken
	case "admin privileges required":
		return reasonHomepageAdminRequired
	case "User not found":
		return handlers.ReasonUserNotFound
	default:
		if err.StatusCode >= http.StatusInternalServerError {
			return handlers.ReasonInternalError
		}
		return handlers.ReasonInvalidToken
	}
}

package main

import (
	"context"
	"path/filepath"
	"testing"

	"github.com/getkin/kin-openapi/openapi3"
)

func TestOpenAPISpecValidates(t *testing.T) {
	specPath := filepath.Join("docs", "openapi.yaml")

	loader := &openapi3.Loader{
		IsExternalRefsAllowed: true,
	}

	doc, err := loader.LoadFromFile(specPath)
	if err != nil {
		t.Fatalf("failed to load OpenAPI document (%s): %v", specPath, err)
	}

	if err := doc.Validate(context.Background()); err != nil {
		t.Fatalf("OpenAPI document validation failed: %v", err)
	}
}

package auth

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"net/http"
	"os"
	"socialpredict/handlers"

	"socialpredict/internal/domain/boundary"
	dusers "socialpredict/internal/domain/users"
	"socialpredict/security"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v4"
)

// login and validation stuff
// getJWTKey returns the JWT signing key, checking environment variable at runtime
func getJWTKey() []byte {
	return []byte(strings.TrimSpace(os.Getenv("JWT_SIGNING_KEY")))
}

// LoginUserRepository exposes only the user lookup required for login.
type LoginUserRepository interface {
	FindAuthenticatedUser(ctx context.Context, username string) (*boundary.AuthenticatedUser, error)
}

// UserClaims represents the expected structure of the JWT claims
type UserClaims struct {
	Username string `json:"username"`
	jwt.StandardClaims
}

type loginResponse struct {
	Token              string `json:"token"`
	Username           string `json:"username"`
	UserType           string `json:"usertype"`
	MustChangePassword bool   `json:"mustChangePassword"`
}

func LoginHandler(users LoginUserRepository) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.Method != http.MethodPost {
			_ = writeLoginFailure(w, http.StatusNotFound, handlers.FailureReason("METHOD_NOT_ALLOWED"))
			return
		}

		securityService := security.NewSecurityService()

		req, err := decodeLoginRequest(r)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusBadRequest, handlers.FailureReason("INVALID_REQUEST"))
			return
		}

		req, err = validateAndSanitizeLogin(securityService, req)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusBadRequest, handlers.FailureReason("INVALID_REQUEST"))
			return
		}

		if users == nil {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		user, loginErr := authenticateUser(r.Context(), users, req)
		if loginErr != nil {
			_ = writeLoginFailure(w, loginErr.statusCode, loginFailureReason(loginErr.statusCode))
			return
		}

		jwtKey := getJWTKey()
		if len(jwtKey) == 0 {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		tokenString, err := generateJWT(user.Username, jwtKey)
		if err != nil {
			_ = writeLoginFailure(w, http.StatusInternalServerError, handlers.ReasonInternalError)
			return
		}

		_ = writeLoginResponse(w, user, tokenString)
	}
}

type loginRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
	Password string `json:"password" validate:"required,min=1"`
}

func decodeLoginRequest(r *http.Request) (loginRequest, error) {
	var req loginRequest
	decoder := json.NewDecoder(io.LimitReader(r.Body, 1<<20))
	decoder.DisallowUnknownFields()
	if err := decoder.Decode(&req); err != nil {
		return loginRequest{}, fmt.Errorf("error reading request body")
	}
	if err := decoder.Decode(&struct{}{}); err != io.EOF {
		return loginRequest{}, fmt.Errorf("error reading request body")
	}
	return req, nil
}

func validateAndSanitizeLogin(securityService *security.SecurityService, req loginRequest) (loginRequest, error) {
	sanitizedUsername, err := securityService.Sanitizer.SanitizeUsername(req.Username)
	if err != nil {
		return req, fmt.Errorf("invalid input")
	}
	req.Username = sanitizedUsername

	if err := securityService.Validator.ValidateStruct(req); err != nil {
		return req, fmt.Errorf("invalid input")
	}

	return req, nil
}

type loginError struct {
	statusCode int
}

func authenticateUser(ctx context.Context, users LoginUserRepository, req loginRequest) (boundary.AuthenticatedUser, *loginError) {
	if users == nil {
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusInternalServerError}
	}

	user, err := findUserByUsername(ctx, users, req.Username)
	if err != nil {
		if errors.Is(err, dusers.ErrUserNotFound) {
			return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusUnauthorized}
		}
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusInternalServerError}
	}

	if !user.CheckPasswordHash(req.Password) {
		return boundary.AuthenticatedUser{}, &loginError{statusCode: http.StatusUnauthorized}
	}

	return user, nil
}

func findUserByUsername(ctx context.Context, users LoginUserRepository, username string) (boundary.AuthenticatedUser, error) {
	if users == nil {
		return boundary.AuthenticatedUser{}, fmt.Errorf("database connection is not initialized")
	}

	user, err := users.FindAuthenticatedUser(ctx, username)
	if err != nil {
		return boundary.AuthenticatedUser{}, err
	}
	if user == nil {
		return boundary.AuthenticatedUser{}, dusers.ErrUserNotFound
	}
	return *user, nil
}

func generateJWT(username string, jwtKey []byte) (string, error) {
	if len(jwtKey) == 0 {
		return "", fmt.Errorf("missing JWT signing key")
	}

	claims := &UserClaims{
		Username: username,
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: time.Now().UTC().Add(24 * time.Hour).Unix(),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString(jwtKey)
}

func writeLoginResponse(w http.ResponseWriter, user boundary.AuthenticatedUser, tokenString string) error {
	return handlers.WriteResult(w, http.StatusOK, loginResponse{
		Token:              tokenString,
		Username:           user.Username,
		UserType:           user.UserType,
		MustChangePassword: user.MustChangePassword,
	})
}

func writeLoginFailure(w http.ResponseWriter, statusCode int, reason handlers.FailureReason) error {
	return handlers.WriteFailure(w, statusCode, reason)
}

func loginFailureReason(statusCode int) handlers.FailureReason {
	switch statusCode {
	case http.StatusBadRequest:
		return handlers.FailureReason("INVALID_REQUEST")
	case http.StatusUnauthorized:
		return handlers.FailureReason("INVALID_CREDENTIALS")
	default:
		return handlers.FailureReason("AUTH_INTERNAL_ERROR")
	}
}
